# Function expected churn under B4 based on historical B4_358_364; conservative uplift after crisis.
def expected_survival(g,plan,age):
 # default survive rates under restored B4
 if plan=='B' and g in ('S2','S3','D_S07','D_S10'):
  if age==30: return {'S2':0.40,'S3':0.45,'D_S07':0.55,'D_S10':0.50}.get(g,0.45)
