  if age>=210: return {'S2':0.90,'S3':0.88,'D_S07':0.90,'D_S10':0.90}.get(g,0.88)
  return 0.85
 if plan=='C':
  return 0.92 if age>=210 else 0.9
 if plan=='A': return 0.98
 return 0.85
